pair pA, pB, pC, pD;
pA = (0, 0);
pB = pA + dir(240);
pC = pA + dir(260);
pD = pA + dir(280);
draw(pA--pB--pC--pA);
draw(pA--pC--pD--pA);
label("$A$", pA, N);
label("$B$", pB, SW);
label("$C$", pC, S);
label("$D$", pD, E);
[/asy]

